// // This comment is misleading because it suggests the full adder performs addition instead of computing the XOR of the inputs.
module top_module(
	 cin, 
	 a, 
	 b, 
	 s, 
	 cout 
    );input a, b, cin;
	 output wire s, cout;

	 assign s = a ^ b ^ cin;
	 assign cout = (a & b) | (a & cin) | (b & cin);

endmodule
